    );

    $links_found = false;
    $output = '';

    foreach ($social_platforms as $id => $data) {
        $url = boldmcqspro_get_option('boldmcqspro_social_' . $id);
        if ($url) {
            $links_found = true;
            $output .= '<a href="' . esc_url($url) . '" target="_blank" rel="noopener noreferrer" class="text-gray-400 hover:text-primary ' . $icon_class . '" aria-label="' . esc_attr($data['label']) . '">';
            $output .= $data['icon'];
            $output .= '</a>';
        }
    }

    if ($links_found) {
        echo '<div class="' . esc_attr($class) . '">' . $output . '</div>';
    } elseif (has_nav_menu('social')) {
        // Fallback to social menu location
        echo '<div class="' . esc_attr($class) . '">';
        wp_nav_menu(array(
            'theme_location' => 'social',
            'menu_class'     => 'flex space-x-4',
            'container'      => false,
            'depth'          => 1,
            'walker'         => new BoldMcqsPro_Social_Walker_Nav_Menu(),
        ));
        echo '</div>';
    }
}
